.github/workflows/quality-gate-pr.yml:
name: Quality Gate PR Check
on: [pull_request]
jobs:
  quality:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v3
        with:
          ref: ${{ github.head_ref }}

      - name: Run Quality Gate on PR
        run: |
          /aem-quality-gate --args '{
            "repositories": [{
              "repoUrl": "${{ github.repository }}",
              "repoName": "pr-check",
              "branch": "${{ github.head_ref }}"
            }]
          }'

      - name: Comment Results on PR
        if: always()
        uses: actions/github-script@v6
        with:
          script: |
            const fs = require('fs');
            const report = JSON.parse(fs.readFileSync('...quality-reports/.../aggregated-report.json'));
            github.rest.issues.createComment({
              issue_number: context.issue.number,
              owner: context.repo.owner,
              repo: context.repo.repo,
              body: `## Quality Gate Results\n\n- Overall Rating: ${report.summary.overallRating}\n- Total Findings: ${report.summary.totalFindings}\n...`
            });
